class Solution {
    public int numberOfArrays(String s, int k) {
        int n = s.length();
        int result = 1;
        for (int i = 0; i < n; i++) {
            int digit = s.charAt(i) - '0';
            result *= (k / digit);
            result %= 1000000007;
            k %= 1000000007;
        }
        return result;
    }
}
